Q_{\tt qjl}^{-1}(\z) := \frac{\sqrt{\pi/2}}{d} \cdot \S^\top \cdot \z ~~~~\text{ for any } \z \in \{ -1, +1\}^d.
\]
\end{definition}

In the next lemma we restate the results from~\cite{qjl} that show the QJL is unbiased and also has small inner product distortion:
\begin{lemma}[performance guarantee: QJL]\label{lem_qjl}
Let $Q_{\tt qjl}$ and $Q_{\tt qjl}^{-1}$ be defined as per \cref{def_qjl}. 
For any vector $\x \in \SS^{d-1}$ and any $\y \in \RR^d$ we have the following:
\begin{itemize}
    \item Unbiased: $\E\left[ \left< \y, Q_{\tt qjl}^{-1}\left( Q_{\tt qjl}(\x) \right) \right> \right] = \langle \y, \x \rangle$.

